mapper.select:
SELECT * FROM ( SELECT ROWNUM AS RNUM, T1.* FROM ( SELECT B.BOARD_NO, B.BOARD_TITLE, M.USER_NAME AS BOARD_WRITER, B.VIEW_COUNT, B.BOARD_DATE FROM BOARD_POST B LEFT JOIN MEMBER M ON B.USER_NO = M.USER_NO WHERE B.BOARD_DELETE = 'N'
AND B.BOARD_CD_NO IN (2, 3)
AND B.BOARD_CD_NO = #{boardCdNo}
ORDER BY B.BOARD_NO DESC ) T1 ) WHERE RNUM BETWEEN #{offset} AND #{limit}

SELECT COUNT(*) FROM BOARD_POST B LEFT JOIN MEMBER M ON B.USER_NO = M.USER_NO WHERE B.BOARD_DELETE = 'N'
AND B.BOARD_CD_NO IN (2, 3)
AND B.BOARD_CD_NO = #{boardCdNo}

